#include <array>
#include <cstddef>
#include <iostream>

template <typename T, std::size_t N>
void reverseArray(std::array<T, N>& arr)
{
    for (std::size_t i{ 0 }; i < N / 2; ++i)
    {
        T temp{ arr[i] };
        arr[i] = arr[N - 1 - i];
        arr[N - 1 - i] = temp;
    }
}

template <typename T, std::size_t N>
void rotateLeft(std::array<T, N>& arr)
{
    T first{ arr[0] };
    for (std::size_t i{ 0 }; i + 1 < N; ++i)
        arr[i] = arr[i + 1];
    arr[N - 1] = first;
}

template <typename T, std::size_t N>
void printArray(const std::array<T, N>& arr)
{
    for (std::size_t i{ 0 }; i < N; ++i)
    {
        if (i > 0)
            std::cout << ' ';
        std::cout << arr[i];
    }
    std::cout << '\n';
}

int main()
{
    std::array<int, 6> arr{};

    for (std::size_t i{ 0 }; i < arr.size(); ++i)
        std::cin >> arr[i];

    reverseArray(arr);
    printArray(arr);

    rotateLeft(arr);
    printArray(arr);

    return 0;
}

