#include <array>
#include <cstddef>
#include <iostream>

template <typename T, std::size_t N>
T computeSum(const std::array<T, N>& arr)
{
    T sum{};
    for (const auto& val : arr)
        sum += val;
    return sum;
}

int main()
{
    int cArr[5]{};

    for (int i{ 0 }; i < 5; ++i)
        std::cin >> cArr[i];

    std::array<int, 5> sArr{};

    const int* ptr{ cArr };
    while (ptr < cArr + 5)
    {
        std::size_t idx{ static_cast<std::size_t>(ptr - cArr) };
        sArr[idx] = *ptr;
        ++ptr;
    }

    int sum{ computeSum(sArr) };

    std::cout << "Array:";
    for (std::size_t i{ 0 }; i < sArr.size(); ++i)
        std::cout << ' ' << sArr[i];
    std::cout << '\n';

    std::cout << "Sum: " << sum << '\n';

    return 0;
}
